#!/usr/bin/env python3
"""Real THREE-node distributed forward: Mac mini + R1 #1 + R1 #2.

24 layers split three ways; the residual crosses the USB wire twice:

    tokens -> /embed (Mac entry) -> /forward 0-8 (Mac entry, native)
           -> [wire] -> /forward 8-16  (R1 #1 mid,  aarch64-musl)
           -> [wire] -> /forward 16-24 (R1 #2 exit, aarch64-musl) -> /lm-head -> argmax

Each station loads the full qwen-0.5b knot and runs only the layer range named in
the X-Layer-Range header. Setup:
  Mac :8080  fat-station --role entry --layers 0..24   (native)
  R1#1       fat-station --role mid   --layers 8..16   ; adb -s <s1> forward tcp:8090 tcp:8090
  R1#2       fat-station --role exit  --layers 16..24  ; adb -s <s2> forward tcp:8091 tcp:8090
"""
import urllib.request, struct, sys, time

MAC  = "http://127.0.0.1:8080"   # Mac entry
R1_1 = "http://127.0.0.1:8090"   # R1 #1 mid   (adb-forwarded)
R1_2 = "http://127.0.0.1:8091"   # R1 #2 exit  (adb-forwarded)
TOKENS = [785, 6722, 315, 9625, 374]   # "The capital of France is" (Qwen)
EXPECT = 12095                          # " Paris"
CUTS = [(MAC, 0, 8, "mac  entry"), (R1_1, 8, 16, "r1#1 mid "), (R1_2, 16, 24, "r1#2 exit")]

def post(base, path, body, headers):
    req = urllib.request.Request(base + path, data=body, method="POST")
    for k, v in headers.items():
        req.add_header(k, v)
    with urllib.request.urlopen(req, timeout=300) as r:
        return r.read()

to_f32 = lambda b: list(struct.unpack("<%df" % (len(b) // 4), b))
u32b   = lambda a: struct.pack("<%dI" % len(a), *a)

seq = len(TOKENS)
t0 = time.time()
buf = post(MAC, "/embed", u32b(TOKENS), {"X-Position": "0"})
hidden = (len(buf) // 4) // seq
print(f"[mac]  /embed          -> {len(buf)//4} f32 (seq={seq} hidden={hidden})")
for base, lo, hi, label in CUTS:
    buf = post(base, "/forward", buf,
               {"X-Position": "0", "X-Sequence-Length": str(seq), "X-Layer-Range": f"{lo}-{hi}"})
    wire = "" if base == MAC else "   (over the USB wire)"
    print(f"[{label}] /forward {lo}-{hi:<2} -> {len(buf)//4} f32{wire}")
logits = to_f32(post(R1_2, "/lm-head", buf, {"X-Sequence-Length": str(seq)}))
argmax = max(range(len(logits)), key=lambda i: logits[i])
dt = (time.time() - t0) * 1000
print(f"[r1#2 exit] /lm-head    -> vocab={len(logits)}")
print(f"\nargmax={argmax} logit={logits[argmax]:.4f}  expect={EXPECT}  ({dt:.0f} ms across 3 nodes)")
ok = argmax == EXPECT
print("RESULT:", "PASS - Mac+R1+R1 three-node forward answers ' Paris'" if ok else f"FAIL (got {argmax})")
sys.exit(0 if ok else 1)
